/**
 * `workflows` stage. Shows the suggested workflows and an "Understood" CTA.
 * Once confirmed, the linear stage cursor advances to `platforms` (handled
 * by the page). This stage is responsible for the workflows display only —
 * platform-connect is its own stage.
 */

"use client";

import * as m from "motion/react-m";
import type { Dispatch } from "react";
import ChatBubbleBot from "@/features/chat/components/bubbles/bot/ChatBubbleBot";
import { BOT_BUBBLE_DEFAULTS } from "../../constants/bubbleDefaults";
import {
  WORKFLOWS_INTRO_PRIMARY,
  WORKFLOWS_INTRO_SECONDARY,
} from "../../constants/messages";
import { MOTION_FADE_UP_LARGE } from "../../constants/motion";
import type { Action, OnboardingState } from "../../state/types";
import { ComposerCTA } from "../ComposerCTA";
import { OnboardingCTAButton } from "../OnboardingCTAButton";
import { OnboardingWorkflowCards } from "../OnboardingWorkflowCards";

interface WorkflowsProps {
  state: OnboardingState;
  dispatch: Dispatch<Action>;
}

export function Workflows({ state }: WorkflowsProps) {
  const workflows = state.server?.suggested_workflows ?? [];
  const workflowsConfirmed = state.workflowsConfirmed;

  if (workflows.length === 0) return null;

  return (
    <m.div className="mt-4 space-y-4" {...MOTION_FADE_UP_LARGE}>
      <ChatBubbleBot
        {...BOT_BUBBLE_DEFAULTS}
        text={`${WORKFLOWS_INTRO_PRIMARY}<NEW_MESSAGE_BREAK>${WORKFLOWS_INTRO_SECONDARY}`}
      >
        <div className="mt-3">
          <OnboardingWorkflowCards workflows={workflows} />
        </div>
        {!workflowsConfirmed && (
          <p className="mt-2 ml-10.75 text-xs text-zinc-600">
            Here's what I set up to get you started:
          </p>
        )}
      </ChatBubbleBot>
    </m.div>
  );
}

export function WorkflowsComposer({ dispatch }: WorkflowsProps) {
  return (
    <ComposerCTA>
      <OnboardingCTAButton
        onClick={() => dispatch({ type: "confirmWorkflows" })}
      >
        Understood
      </OnboardingCTAButton>
    </ComposerCTA>
  );
}

export const REVEAL_TODOS_INTRO_GMAIL =
  "You can add todos and I will run them automatically. This keeps your todo list moving so it never piles up.<NEW_MESSAGE_BREAK>I drafted a few from your inbox that I think are worth doing. Try one:";

export const REVEAL_TODOS_INTRO_NO_GMAIL =
  "You can add todos and I will run them automatically. This keeps your todo list moving so it never piles up.<NEW_MESSAGE_BREAK>Based on what you want to get done, I drafted a few worth doing. Try one:";

// ── Workflows stage copy ────────────────────────────────────────────────────

export const WORKFLOWS_INTRO_PRIMARY =
  "Workflows are recurring jobs I run across your tools like Gmail, Calendar, Notion, and Slack, on a schedule or triggered by an event like a new email.";

export const WORKFLOWS_INTRO_SECONDARY =
  "They handle the everyday grunt work for you. I've put together a few tailored to how you work, build more anytime in the Workflows page.";

