547	  }, [text]);
548	
549	  const processedTools = React.useMemo(() => {
550	    const grouped = new Map<ToolName, ToolDataMap[ToolName][]>();
551	    const individual: ToolDataEntry[] = [];
552	
553	    tool_data?.forEach((entry) => {
554	      const toolName = entry.tool_name as ToolName;
555	      if (GROUPED_TOOLS.has(toolName)) {
556	        if (!grouped.has(toolName)) grouped.set(toolName, []);
557	        grouped.get(toolName)!.push(entry.data);
558	      } else {
559	        individual.push(entry);
560	      }
561	    });
562	
563	    const groupedEntries: ToolDataEntry[] = Array.from(grouped.entries()).map(
564	      ([toolName, dataArray]) => ({
565	        tool_name: toolName,
566	        tool_category: "",
567	        data: dataArray as ToolDataMap[ToolName],
568	        timestamp: null,
569	      }),
570	    );
571	
572	    return [...groupedEntries, ...individual];
573	  }, [tool_data]);
574	
575	  return (
576	    <>
577	      {parsedContent.thinking && (
578	        <ThinkingBubble thinkingContent={parsedContent.thinking} />
579	      )}
580	
581	      {processedTools.map((entry, index) => {
582	        const toolName = entry.tool_name as ToolName;
583	        const keyId = entry.timestamp || index;
584	
585	        if (toolName === "todo_progress") {
586	          const data = getTypedData(entry as ToolDataUnion, "todo_progress");
587	          return data ? (
588	            <React.Fragment key={`${baseId}-tool-${toolName}-${keyId}`}>
589	              <TodoProgressSection
590	                todo_progress={data as TodoProgressData}
591	                isStreaming={loading}
592	              />
593	            </React.Fragment>
594	          ) : null;
595	        }
596	
597	        const renderer = TOOL_RENDERERS[toolName];
598	        if (!renderer) return null;
599	
600	        const typedData = getTypedData(entry as ToolDataUnion, toolName);
601	        if (!typedData) return null;
602	
603	        const toolCallId =
604	          typeof typedData === "object" &&
605	          typedData !== null &&
606	          "tool_call_id" in typedData
607	            ? String(
608	                (typedData as unknown as { tool_call_id?: string })
609	                  .tool_call_id ?? "",
610	              )
611	            : "";
612	        const toolKey = toolCallId
613	          ? `${baseId}-tool-${toolName}-${toolCallId}`
614	          : `${baseId}-tool-${toolName}-${index}`;
615	
616	        return (
617	          <React.Fragment key={toolKey}>
618	            {renderTool(toolName, typedData, index)}
619	          </React.Fragment>
620	        );
621	      })}
622	
623	      {shouldShowTextBubble(text, isConvoSystemGenerated, systemPurpose) &&
624	        (() => {
625	          const displayText = parsedContent.cleanText || "";
626	          const textParts = displayText.includes(":::openui")
627	            ? splitByBreaksPreservingFences(displayText)
628	            : splitMessageByBreaks(displayText);
629	
630	          return (
631	            <div className="flex flex-col">
632	              {textParts.map((part, index) => {
633	                const isFirst = index === 0;
634	                const isLast = index === textParts.length - 1;
635	                const isSingle = textParts.length === 1;
636	                const segments = parseOpenUISegments(part, !!loading);
637	                const hasOpenUI = segments.some((s) => s.type === "openui");
638	
639	                // ── Pure markdown part — normal iMessage bubble ──────────────
640	                if (!hasOpenUI) {
641	                  const isEmojiOnly = isOnlyEmojis(part);
642	                  const emojiCount = isEmojiOnly ? getEmojiCount(part) : 0;
643	
644	                  let groupedClasses = isSingle
645	                    ? "imessage-grouped-last"
646	                    : isFirst
647	                      ? "imessage-grouped-first mb-1.5"
648	                      : isLast
649	                        ? "imessage-grouped-last"
650	                        : "imessage-grouped-middle mb-1.5";
651	
652	                  let bubbleClassName = "imessage-bubble imessage-from-them";
653	                  let textClass = "";
654	
655	                  if (isEmojiOnly) {
656	                    if (emojiCount === 1) {
657	                      bubbleClassName = "select-none";
658	                      groupedClasses = "";
659	                      textClass = "text-[4rem] leading-none";
660	                    } else if (emojiCount === 2) {
661	                      textClass = "text-5xl";
662	                    } else if (emojiCount === 3) {
663	                      textClass = "text-4xl";
664	                    }
665	                  }
666	
667	                  return (
668	                    <m.div
669	                      // biome-ignore lint/suspicious/noArrayIndexKey: array is stable
670	                      key={`${baseId}-text-part-${index}`}
671	                      className={`${bubbleClassName} ${groupedClasses}`}
672	                      initial={{ opacity: 0, y: 6 }}
673	                      animate={{ opacity: 1, y: 0 }}
674	                      transition={{
675	                        duration: MESSAGE_BREAK_DURATION_SECONDS,
676	                        ease: MESSAGE_BREAK_EASE_OUT_QUART,
677	                        delay: index * MESSAGE_BREAK_STAGGER_SECONDS,
678	                      }}
679	                    >
680	                      <div className={textClass}>
681	                        <div className="flex flex-col gap-3">
682	                          <MarkdownRenderer
683	                            content={part}
684	                            isStreaming={loading}
685	                          />
686	                          {!!disclaimer && isLast && (
687	                            <Chip
688	                              className="text-xs font-medium text-warning-500"
689	                              color="warning"
690	                              size="sm"
691	                              startContent={
692	                                <Alert01Icon
693	                                  className="text-warning-500"
694	                                  height={17}
695	                                />
696	                              }
697	                              variant="flat"
698	                            >
699	                              {disclaimer}
700	                            </Chip>
701	                          )}
702	                        </div>
703	                      </div>
704	                    </m.div>
705	                  );
706	                }
707	
708	                // ── Mixed part: openui segments render OUTSIDE the bubble ────
709	                // OpenUI components use bg-zinc-800 which would be invisible
710	                // inside the imessage-from-them bubble (same background color).
711	                // Markdown segments get their own compact bubbles; openui
712	                // segments are rendered at the same level as tool cards.
713	                const lastMdIdx = segments.reduce(
714	                  (acc, s, i) =>
715	                    s.type === "markdown" && s.content.trim() ? i : acc,
716	                  -1,
717	                );
718	
719	                return (
720	                  <m.div
721	                    // biome-ignore lint/suspicious/noArrayIndexKey: array is stable
722	                    key={`${baseId}-text-part-${index}`}
723	                    className="flex flex-col"
724	                    initial={{ opacity: 0, y: 6 }}
725	                    animate={{ opacity: 1, y: 0 }}
726	                    transition={{
727	                      duration: MESSAGE_BREAK_DURATION_SECONDS,
728	                      ease: MESSAGE_BREAK_EASE_OUT_QUART,
729	                      delay: index * MESSAGE_BREAK_STAGGER_SECONDS,
730	                    }}
731	                  >
732	                    {segments.map((seg, segIdx) => {
733	                      const segKey = `${baseId}-seg-${index}-${segIdx}`;
734	                      if (seg.type === "openui") {
735	                        return (
736	                          <OpenUIRenderer
737	                            key={segKey}
738	                            code={seg.content}
739	                            isStreaming={!!loading && !seg.isComplete}
740	                          />
741	                        );
742	                      }
743	                      if (!seg.content.trim()) return null;
744	                      const isLastMdInLastPart = isLast && segIdx === lastMdIdx;
745	                      return (
746	                        <div
747	                          key={segKey}
748	                          className={`imessage-bubble imessage-from-them ${isLastMdInLastPart ? "imessage-grouped-last" : "imessage-grouped-first"} mb-1.5`}
749	                        >
750	                          <MarkdownRenderer
751	                            content={seg.content}
752	                            isStreaming={
753	                              !!loading && segIdx === segments.length - 1
754	                            }
755	                          />
756	                          {!!disclaimer && isLastMdInLastPart && (
757	                            <Chip
758	                              className="text-xs font-medium text-warning-500"
759	                              color="warning"
760	                              size="sm"
761	                              startContent={
762	                                <Alert01Icon
763	                                  className="text-warning-500"
764	                                  height={17}
765	                                />
766	                              }
767	                              variant="flat"
768	                            >
769	                              {disclaimer}
770	                            </Chip>
771	                          )}
772	                        </div>
773	                      );
774	                    })}
775	                  </m.div>
776	                );
777	              })}
778	            </div>
779	          );
780	        })()}
781	    </>
782	  );
783	}
